import React, { Component } from 'react';

class About extends Component {
    render() {
        return (
            <div className="about-style">
                <h1>About</h1>
                <div className="about-pane-holder">
                    <p>Howdy! I'm Helena!</p>
                    <p>I'm a 3rd year CS major at Georgia Tech.</p>
                    <p>I love music, video games, & Spider-Man.</p>
                </div>
                {/* <Card/> */}
            </div>
        )
    }
}

export default About;
